    Color(0xFF4CAF50), //  9 - green
    Color(0xFFF44336), // 10 - red
    Color(0xFF00E5FF), // 11 - cyan accent
    Color(0xFFCDDC39), // 12 - lime
  ];

  Color _rankColor(int rank) {
    return _rankColors[(rank - 1) % _rankColors.length];
  }

  @override
  void initState() {
    super.initState();
    _loadLikes();
  }

  Future<String?> _getToken() async {
