import 'dart:async';
import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';
import 'package:web_socket_channel/web_socket_channel.dart';
import 'package:http/http.dart' as http;
import 'package:flutter_slidable/flutter_slidable.dart';

const _baseUrl = 'http://10.0.2.2:8000';
const _wsUrl = 'ws://10.0.2.2:8000';

class _WhoLikesMeEntry {
  final int id;
  final String username;
  final int? age;
  final String? sex;
  final String? photoUrl;
  int? myRankToThem;

  _WhoLikesMeEntry({
    required this.id,
    required this.username,
    this.age,
    this.sex,
    this.photoUrl,
    this.myRankToThem,
  });

  factory _WhoLikesMeEntry.fromJson(Map<String, dynamic> json) {
    return _WhoLikesMeEntry(
      id: json['id'] as int,
      username: json['username'] as String,
      age: json['age'] as int?,
      sex: json['sex'] as String?,
      photoUrl: json['photo_url'] as String?,
      myRankToThem: json['my_rank_to_them'] as int?,
    );
  }
}

class _IncomingLockInfo {
  final int id;
  final DateTime expiresAt;
  final int likerUserId;
  final String likerUsername;

  _IncomingLockInfo({
    required this.id,
    required this.expiresAt,
    required this.likerUserId,
    required this.likerUsername,
  });

  factory _IncomingLockInfo.fromJson(Map<String, dynamic> json) {
    final likerUser = (json['liker_user'] as Map<String, dynamic>?) ??
        (json['locked_user'] as Map<String, dynamic>?) ??
        {};
    return _IncomingLockInfo(
      id: json['id'] as int,
      expiresAt: DateTime.parse(json['expires_at'] as String),
      likerUserId:
          (likerUser['id'] as int?) ?? (json['liker_id'] as int?) ?? 0,
      likerUsername: (likerUser['username'] as String?) ?? '',
    );
  }
}

class WhoLikesMeScreen extends StatefulWidget {
  const WhoLikesMeScreen({super.key});

  @override
  State<WhoLikesMeScreen> createState() => _WhoLikesMeScreenState();
}

class _WhoLikesMeScreenState extends State<WhoLikesMeScreen> {
  List<_WhoLikesMeEntry> _entries = [];
  bool _loading = true;
  String? _error;
  final Set<int> _likedBack = {};
  _IncomingLockInfo? _incomingLock;

  WebSocketChannel? _wsChannel;
  StreamSubscription? _wsSub;
  int? _currentUserId;

  // Datetris rank colours
  static const _rankColors = [
    Color(0xFFFFC107), // 1 - amber
    Color(0xFFFF9800), // 2 - orange
    Color(0xFFE91E8C), // 3 - pink
    Color(0xFF9E9E9E), // 4+
  ];

  Color _rankColor(int? rank) {
    if (rank == null) return const Color(0xFF9E9E9E);
    if (rank <= 3) return _rankColors[rank - 1];
    return _rankColors[3];
  }

  @override
  void initState() {
    super.initState();
    _init();
  }

  Future<void> _init() async {
    await _fetchData();
    await _connectWebSocket();
  }

  Future<String?> _getToken() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getString('jwt_token');
  }

  Future<void> _fetchData() async {
    try {
      final token = await _getToken();
      if (token == null) {
        setState(() {
          _error = 'Not logged in';
          _loading = false;
        });
        return;
      }
      final headers = {'Authorization': 'Bearer $token'};

      final results = await Future.wait([
        http.get(Uri.parse('$_baseUrl/api/users/me'), headers: headers),
        http.get(Uri.parse('$_baseUrl/api/who_likes_me'), headers: headers),
        http.get(Uri.parse('$_baseUrl/api/daily-lock'), headers: headers),
      ]);

      final meRes = results[0];
      final res = results[1];
      final lockRes = results[2];

      if (meRes.statusCode == 200) {
        _currentUserId = (json.decode(meRes.body))['id'] as int?;
      }

      _IncomingLockInfo? incomingLock;
      if (lockRes.statusCode == 200) {
        try {
          final lockData = json.decode(lockRes.body) as Map<String, dynamic>;
          final asLiked = lockData['as_liked'] as Map<String, dynamic>?;
          if (asLiked != null && asLiked['status'] == 'pending') {
            incomingLock = _IncomingLockInfo.fromJson(asLiked);
          }
        } catch (_) {}
      }

      if (res.statusCode == 200) {
        final data = json.decode(res.body);
        final List<dynamic> users = data['users'] ?? [];
        setState(() {
          _entries = users
              .map((u) =>
                  _WhoLikesMeEntry.fromJson(u as Map<String, dynamic>))
              .toList();
          _incomingLock = incomingLock;
          _loading = false;
        });
      } else {
        setState(() {
          _error = 'Failed (${res.statusCode})';
          _loading = false;
        });
      }
    } catch (e) {
      setState(() {
        _error = 'Error: $e';
        _loading = false;
      });
    }
  }

  Future<void> _connectWebSocket() async {
    if (_currentUserId == null) return;
    final token = await _getToken();
    if (token == null) return;
    try {
      final uri = Uri.parse('$_wsUrl/api/ws/rank_updates/$_currentUserId');
      _wsChannel = WebSocketChannel.connect(uri);
      _wsSub = _wsChannel!.stream.listen(
        (message) => _handleWsMessage(message as String),
        onError: (e) => debugPrint('[WhoLikesMe WS] error: $e'),
        onDone: () => debugPrint('[WhoLikesMe WS] closed'),
      );
      debugPrint('[WhoLikesMe WS] connected for user $_currentUserId');
    } catch (e) {
      debugPrint('[WhoLikesMe WS] connect failed: $e');
    }
  }

  void _handleWsMessage(String raw) {
    try {
      final data = json.decode(raw) as Map<String, dynamic>;
      if (data['type'] == 'rank_update') {
        final fromUsername = data['from_username'] as String?;
        final newRank = data['new_rank'] as int?;
        if (fromUsername == null || newRank == null) return;
        setState(() {
          final idx =
              _entries.indexWhere((e) => e.username == fromUsername);
          if (idx != -1) _entries[idx].myRankToThem = newRank;
        });
      }
    } catch (_) {}
  }

  Future<void> _deleteLike(_WhoLikesMeEntry entry) async {
    setState(() => _entries.removeWhere((e) => e.id == entry.id));
    final token = await _getToken();
    if (token == null) return;
    try {
      await http.delete(
        Uri.parse('$_baseUrl/api/like/${entry.id}'),
        headers: {'Authorization': 'Bearer $token'},
      );
      if (mounted) {
        ScaffoldMessenger.of(context)
            .showSnackBar(const SnackBar(content: Text('Removed')));
      }
    } catch (e) {
      debugPrint('[WhoLikesMe] deleteLike error: $e');
    }
  }

  Future<void> _blockUser(_WhoLikesMeEntry entry) async {
    setState(() => _entries.removeWhere((e) => e.id == entry.id));
    final token = await _getToken();
    if (token == null) return;
    try {
      await http.post(
        Uri.parse('$_baseUrl/api/block'),
        headers: {
          'Authorization': 'Bearer $token',
          'Content-Type': 'application/json',
        },
        body: json.encode({'blocked_user_id': entry.id}),
      );
    } catch (e) {
      debugPrint('[WhoLikesMe] blockUser error: $e');
    }
  }

  Future<void> _likeBack(_WhoLikesMeEntry entry) async {
    final token = await _getToken();
    if (token == null) return;
    try {
      final res = await http.post(
        Uri.parse('$_baseUrl/api/like'),
        headers: {
          'Authorization': 'Bearer $token',
          'Content-Type': 'application/json',
        },
        body: json.encode({'liked_user_id': entry.id}),
      );
      if (res.statusCode == 200) {
        final data = json.decode(res.body) as Map<String, dynamic>;
        final status = data['status'] as String?;
        if (status == 'matched') {
          setState(() => _entries.removeWhere((e) => e.id == entry.id));
          if (mounted) {
            ScaffoldMessenger.of(context).showSnackBar(
              const SnackBar(content: Text('🎉 It\'s a match!')),
            );
          }
        } else {
          setState(() => _likedBack.add(entry.id));
          if (mounted) {
            ScaffoldMessenger.of(context).showSnackBar(
              const SnackBar(content: Text('❤️ Like sent!')),
            );
          }
        }
      } else {
        final body = res.body;
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(content: Text('Error ${res.statusCode}: $body')),
          );
        }
      }
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('Error: $e')),
        );
      }
    }
  }

  Future<void> _respondToLock(int lockId, String action) async {
    final token = await _getToken();
    if (token == null) return;
    try {
      final res = await http.post(
        Uri.parse('$_baseUrl/api/daily-lock/$lockId/respond'),
        headers: {
          'Authorization': 'Bearer $token',
          'Content-Type': 'application/json',
        },
        body: json.encode({'action': action}),
      );
      if (res.statusCode == 200 && mounted) {
        setState(() => _incomingLock = null);
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
              content: Text(action == 'like' ? '❤️ Liked back!' : 'Passed')),
        );
      } else if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('Error ${res.statusCode}')),
        );
      }
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(context)
            .showSnackBar(SnackBar(content: Text('Error: $e')));
      }
    }
  }

  @override
  void dispose() {
    _wsSub?.cancel();
    _wsChannel?.sink.close();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: const Color(0xFF0E0E0E),
      appBar: AppBar(
        backgroundColor: const Color(0xFF0E0E0E),
        elevation: 0,
        centerTitle: true,
        title: const Column(
          children: [
            Text(
              'WHO LIKES ME',
              style: TextStyle(
                color: Colors.white,
                fontWeight: FontWeight.bold,
                fontSize: 16,
                letterSpacing: 1.2,
              ),
            ),
            Text(
              'Swipe left to remove · Swipe right to block',
              style: TextStyle(color: Colors.white38, fontSize: 11),
            ),
          ],
        ),
      ),
      body: _buildBody(),
    );
  }

  Widget _buildBody() {
    if (_loading) {
      return const Center(
          child: CircularProgressIndicator(color: Color(0xFFFFC107)));
    }
    if (_error != null) {
      return Center(
          child:
              Text(_error!, style: const TextStyle(color: Colors.redAccent)));
    }

    return Column(
      children: [
        if (_incomingLock != null) _buildIncomingLockBanner(_incomingLock!),
        Expanded(
          child: _entries.isEmpty
              ? RefreshIndicator(
                  onRefresh: _fetchData,
                  color: const Color(0xFFFFC107),
                  child: ListView(children: const [
                    SizedBox(height: 200),
                    Center(
                        child: Column(children: [
                      Icon(Icons.favorite_border,
                          size: 64, color: Color(0xFFFFC107)),
                      SizedBox(height: 16),
                      Text('No one has liked you yet',
                          style:
                              TextStyle(color: Colors.white70, fontSize: 16)),
                    ])),
                  ]),
                )
              : RefreshIndicator(
                  onRefresh: _fetchData,
                  color: const Color(0xFFFFC107),
                  child: ListView.builder(
                    padding: const EdgeInsets.only(top: 8, bottom: 80),
                    itemCount: _entries.length,
                    itemBuilder: (context, index) =>
                        _buildTile(_entries[index]),
                  ),
                ),
        ),
      ],
    );
  }

  Widget _buildIncomingLockBanner(_IncomingLockInfo lock) {
    final hoursLeft = lock.expiresAt.difference(DateTime.now()).inHours;
    return Container(
      margin: const EdgeInsets.fromLTRB(12, 12, 12, 4),
      padding: const EdgeInsets.all(16),
      decoration: BoxDecoration(
        color: const Color(0xFF001520),
        borderRadius: BorderRadius.circular(12),
        border: Border.all(color: Colors.blueAccent, width: 1.5),
        boxShadow: [
          BoxShadow(
            color: Colors.blueAccent.withOpacity(0.15),
            blurRadius: 14,
            spreadRadius: 2,
          ),
        ],
      ),
      child: Column(
        children: [
          const Row(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              Text('⏰', style: TextStyle(fontSize: 16)),
              SizedBox(width: 8),
              Text(
                'Someone has you as #1!',
                style: TextStyle(
                  color: Colors.white,
                  fontSize: 14,
                  fontWeight: FontWeight.bold,
                ),
              ),
            ],
          ),
          const SizedBox(height: 6),
          Text(
            'You have $hoursLeft hour${hoursLeft == 1 ? '' : 's'} to respond',
            style: const TextStyle(color: Colors.white54, fontSize: 12),
          ),
          const SizedBox(height: 12),
          _FlipCountdown(expiresAt: lock.expiresAt, accentColor: Colors.blueAccent),
          const SizedBox(height: 16),
          Row(
            mainAxisAlignment: MainAxisAlignment.spaceEvenly,
            children: [
              ElevatedButton.icon(
                onPressed: () => _respondToLock(lock.id, 'like'),
                icon: const Icon(Icons.favorite, size: 16),
                label: const Text('Like Back'),
                style: ElevatedButton.styleFrom(
                  backgroundColor: Colors.pinkAccent,
                  foregroundColor: Colors.white,
                  padding:
                      const EdgeInsets.symmetric(horizontal: 20, vertical: 10),
                ),
              ),
              OutlinedButton.icon(
                onPressed: () => _respondToLock(lock.id, 'ignore'),
                icon: const Icon(Icons.close, size: 16),
                label: const Text('Pass'),
                style: OutlinedButton.styleFrom(
                  foregroundColor: Colors.white54,
                  side: const BorderSide(color: Colors.white24),
                  padding:
                      const EdgeInsets.symmetric(horizontal: 20, vertical: 10),
                ),
              ),
            ],
          ),
        ],
      ),
    );
  }

  Widget _buildTile(_WhoLikesMeEntry entry) {
    final rank = entry.myRankToThem;
    final rankColor = _rankColor(rank);
    final photoUrl =
        entry.photoUrl?.replaceFirst('http://0.0.0.0:8000', _baseUrl) ??
            '$_baseUrl/api/users/${entry.id}/photo';

    return Slidable(
      key: ValueKey(entry.id),
      startActionPane: ActionPane(
        motion: const BehindMotion(),
        extentRatio: 0.25,
        children: [
          SlidableAction(
            onPressed: (_) => _blockUser(entry),
            backgroundColor: const Color(0xFFFF9800),
            foregroundColor: Colors.white,
            icon: Icons.block,
            label: 'Block',
            borderRadius: BorderRadius.circular(8),
          ),
        ],
      ),
      endActionPane: ActionPane(
        motion: const BehindMotion(),
        extentRatio: 0.25,
        children: [
          SlidableAction(
            onPressed: (_) => _deleteLike(entry),
            backgroundColor: Colors.redAccent,
            foregroundColor: Colors.white,
            icon: Icons.delete_outline,
            label: 'Remove',
            borderRadius: BorderRadius.circular(8),
          ),
        ],
      ),
      child: Column(
        children: [
          Padding(
            padding:
                const EdgeInsets.symmetric(horizontal: 16, vertical: 14),
            child: Row(
              children: [
                // Rank number
                SizedBox(
                  width: 40,
                  child: Text(
                    rank != null ? '$rank' : '—',
                    style: TextStyle(
                      color: rankColor,
                      fontSize: 28,
                      fontWeight: FontWeight.bold,
                    ),
                  ),
                ),
                // Dot indicators (age/sex badges)
                Column(
                  children: [
                    if (entry.age != null)
                      _badge('${entry.age}', Colors.amber),
                    if (entry.sex != null)
                      _badge(entry.sex![0].toUpperCase(), Colors.blueAccent),
                  ],
                ),
                const SizedBox(width: 12),
                // Avatar
                CircleAvatar(
                  radius: 24,
                  backgroundColor: Colors.white12,
                  child: ClipOval(
                    child: Image.network(
                      photoUrl,
                      width: 48,
                      height: 48,
                      fit: BoxFit.cover,
                      errorBuilder: (_, __, ___) => Text(
                        entry.username.isNotEmpty
                            ? entry.username[0].toUpperCase()
                            : '?',
                        style: const TextStyle(
                            color: Colors.white,
                            fontSize: 18,
                            fontWeight: FontWeight.bold),
                      ),
                    ),
                  ),
                ),
                const SizedBox(width: 14),
                // Name
                Expanded(
                  child: Text(
                    entry.username,
                    style: const TextStyle(
                      color: Colors.white,
                      fontSize: 16,
                      fontWeight: FontWeight.w600,
                    ),
                  ),
                ),
                // Heart like-back button
                IconButton(
                  onPressed: _likedBack.contains(entry.id)
                      ? null
                      : () => _likeBack(entry),
                  icon: Icon(
                    _likedBack.contains(entry.id)
                        ? Icons.favorite
                        : Icons.favorite_border,
                    color: _likedBack.contains(entry.id)
                        ? Colors.red
                        : Colors.white54,
                    size: 26,
                  ),
                  padding: EdgeInsets.zero,
                  constraints:
                      const BoxConstraints(minWidth: 36, minHeight: 36),
                ),
                const SizedBox(width: 6),
                // Green play button
                Container(
                  width: 40,
                  height: 40,
                  decoration: const BoxDecoration(
                    color: Color(0xFF00C853),
                    shape: BoxShape.circle,
                  ),
                  child:
                      const Icon(Icons.play_arrow, color: Colors.white, size: 22),
                ),
              ],
            ),
          ),
          const Divider(height: 1, color: Colors.white10),
        ],
      ),
    );
  }

  Widget _badge(String label, Color color) {
    return Container(
      margin: const EdgeInsets.only(bottom: 2),
      padding: const EdgeInsets.symmetric(horizontal: 5, vertical: 1),
      decoration: BoxDecoration(
        color: color.withOpacity(0.2),
        borderRadius: BorderRadius.circular(4),
        border: Border.all(color: color.withOpacity(0.5)),
      ),
      child: Text(label,
          style: TextStyle(
              color: color, fontSize: 10, fontWeight: FontWeight.bold)),
    );
  }
}

// ── Flip countdown ────────────────────────────────────────────────────────────

class _FlipCountdown extends StatefulWidget {
  final DateTime expiresAt;
  final Color accentColor;
  const _FlipCountdown({
    required this.expiresAt,
    this.accentColor = const Color(0xFFFFC107),
  });

  @override
  State<_FlipCountdown> createState() => _FlipCountdownState();
}

class _FlipCountdownState extends State<_FlipCountdown> {
  late Timer _timer;
  Duration _remaining = Duration.zero;

  @override
  void initState() {
    super.initState();
    _update();
    _timer = Timer.periodic(const Duration(seconds: 1), (_) => _update());
  }

  void _update() {
    final r = widget.expiresAt.difference(DateTime.now());
    setState(() => _remaining = r.isNegative ? Duration.zero : r);
  }

  @override
  void dispose() {
    _timer.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final h = _remaining.inHours.toString().padLeft(2, '0');
    final m = (_remaining.inMinutes % 60).toString().padLeft(2, '0');
    final s = (_remaining.inSeconds % 60).toString().padLeft(2, '0');
    return Row(
      mainAxisAlignment: MainAxisAlignment.center,
      children: [
        _seg(h, 'h'),
        _sep(),
        _seg(m, 'm'),
        _sep(),
        _seg(s, 's'),
      ],
    );
  }

  Widget _seg(String val, String prefix) => Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          for (int i = 0; i < val.length; i++) _digit(val[i], '$prefix$i'),
        ],
      );

  Widget _digit(String d, String keyPrefix) => AnimatedSwitcher(
        duration: const Duration(milliseconds: 220),
        transitionBuilder: (child, anim) => ScaleTransition(
          scale: anim,
          child: FadeTransition(opacity: anim, child: child),
        ),
        child: Container(
          key: ValueKey('$keyPrefix:$d'),
          width: 30,
          height: 44,
          margin: const EdgeInsets.symmetric(horizontal: 1.5),
          decoration: BoxDecoration(
            color: widget.accentColor.withOpacity(0.08),
            borderRadius: BorderRadius.circular(5),
            border: Border.all(
                color: widget.accentColor.withOpacity(0.35), width: 1),
          ),
          alignment: Alignment.center,
          child: Text(
            d,
            style: TextStyle(
              color: widget.accentColor,
              fontSize: 24,
              fontWeight: FontWeight.bold,
            ),
          ),
        ),
      );

  Widget _sep() => Padding(
        padding: const EdgeInsets.only(left: 3, right: 3, bottom: 4),
        child: Text(
          ':',
          style: TextStyle(
              color: widget.accentColor,
              fontSize: 28,
              fontWeight: FontWeight.bold),
        ),
      );
}

